namespace NotificationsApp.Services;

public class Notification
{
    public int Id { get; set; }
    public string Message { get; set; } = "";
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed initial fake data
        _notifications.AddRange(new[]
        {
            new Notification { Id = _nextId++, Message = "Welcome to the app!", Timestamp = DateTime.UtcNow.AddMinutes(-10) },
            new Notification { Id = _nextId++, Message = "Your profile was created.", Timestamp = DateTime.UtcNow.AddMinutes(-5) },
            new Notification { Id = _nextId++, Message = "You have a new follower.", Timestamp = DateTime.UtcNow.AddMinutes(-2) },
        });
    }

    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.OrderByDescending(n => n.Timestamp).ToList());
        }
    }

    public Task<List<Notification>> GetNotificationsSinceAsync(int lastSeenId)
    {
        lock (_lock)
        {
            // Simulate a new notification appearing roughly every 15 seconds
            if (Random.Shared.Next(3) == 0)
            {
                _notifications.Add(new Notification
                {
                    Id = _nextId++,
                    Message = $"New event at {DateTime.UtcNow:T}",
                    Timestamp = DateTime.UtcNow,
                });
            }

            var newer = _notifications
                .Where(n => n.Id > lastSeenId)
                .OrderByDescending(n => n.Timestamp)
                .ToList();

            return Task.FromResult(newer);
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService NotificationSvc
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (notifications is not null)
    {
        <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
    }
</h1>

@if (notifications is null)
{
    <p><em>Loading...</em></p>
}
else if (notifications.Count == 0)
{
    <p>No notifications yet.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("g")</small>
            </li>
        }
    </ul>
}

@code {
    [PersistentState]
    public List<Notification>? notifications { get; set; }

    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    protected override async Task OnInitializedAsync()
    {
        // Only fetch if state was NOT restored from prerender
        if (notifications is null)
        {
            notifications = await NotificationSvc.GetNotificationsAsync();
        }

        _lastSeenId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // Start polling only after the page is interactive (never during prerender)
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                var newer = await NotificationSvc.GetNotificationsSinceAsync(_lastSeenId);
                if (newer.Count > 0)
                {
                    notifications = newer.Concat(notifications!).ToList();
                    _lastSeenId = notifications.Max(n => n.Id);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (TaskCanceledException)
            {
                // Expected on disposal — exit cleanly
                break;
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

