namespace NotificationsApp.Services;

public class Notification
{
    public int Id { get; set; }
    public string Message { get; set; } = "";
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        _notifications.AddRange(new[]
        {
            new Notification { Id = _nextId++, Message = "Welcome to the app!", Timestamp = DateTime.UtcNow.AddMinutes(-10) },
            new Notification { Id = _nextId++, Message = "Your profile was created.", Timestamp = DateTime.UtcNow.AddMinutes(-5) },
            new Notification { Id = _nextId++, Message = "You have a new follower.", Timestamp = DateTime.UtcNow.AddMinutes(-2) },
        });
    }

    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.OrderByDescending(n => n.Timestamp).ToList());
        }
    }

    public Task<List<Notification>> GetNotificationsSinceAsync(int lastSeenId)
    {
        lock (_lock)
        {
            // Simulate a new notification appearing roughly every 15 seconds
            if (Random.Shared.Next(3) == 0)
            {
                _notifications.Add(new Notification
                {
                    Id = _nextId++,
                    Message = $"New event at {DateTime.UtcNow:T}",
                    Timestamp = DateTime.UtcNow,
                });
            }

            var newer = _notifications
                .Where(n => n.Id > lastSeenId)
                .OrderByDescending(n => n.Timestamp)
                .ToList();

            return Task.FromResult(newer);
        }
    }
}

